SELECT AVG(mean_price) AS average_price
FROM price_analytics
WHERE region_id = 1;

SELECT pc.category_name, pa.mean_price
FROM price_analytics pa
INNER JOIN price_categories pc ON pa.price_id = pc.price_id;

SELECT DISTINCT AVG(price_p1_var + price_p2_var + price_p3_var + price_p1_fix + price_p2_fix + price_p3_fix) AS avg_price
FROM prices
WHERE model_id = 0 AND region_id = 1;

SELECT COUNT(category_name) AS off_peak_count
FROM price_categories
WHERE category_name = 'Off-Peak';

SELECT AVG(price_p1_var) AS avg_price_p1_var
FROM prices
WHERE model_id = (SELECT model_id FROM pricing_models WHERE model_name = 'Premium Pricing Model');
